from collections import Counter
from sympy import factorint
def A394591(n): # more efficient for large n
    c = Counter()
    for i in range(2*n+1,3*n+1):
        c += factorint(i)
    for i in range(2,n+1):
        c -= factorint(i)
    return sum(c) # _Chai Wah Wu_, Apr 27 2026

